pub struct Board {
    pub id: String,
    pub name: String,
    pub created_at: String,
    pub updated_at: String,
}

/// A column within a board, holding tasks in order.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Column {
    pub id: String,
    pub board_id: String,
    pub name: String,
    pub position: i32,
    pub created_at: String,
    pub updated_at: String,
}

/// A priority level (e.g. low, medium, high).
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Priority {
    pub id: String,
    pub name: String,
}

/// A task belonging to a column.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Task {
    pub id: String,
