        let items = vec![("b".into(), 2), ("a".into(), 0), ("c".into(), 1)];
        let result = recompute_positions(&items);
        assert_eq!(result, vec![("a".into(), 0), ("c".into(), 1), ("b".into(), 2)]);
    }

    #[test]
    fn positions_after_insert_at_end() {
        let existing = vec![("a".into(), 0), ("b".into(), 1)];
        let result = positions_after_insert(&existing, 2);
        // Items unchanged, new item would be at 2
        assert_eq!(result, vec![("a".into(), 0), ("b".into(), 1)]);
    }

    #[test]
    fn positions_after_insert_at_beginning() {
        let existing = vec![("a".into(), 0), ("b".into(), 1)];
        let result = positions_after_insert(&existing, 0);
        assert_eq!(result, vec![("a".into(), 1), ("b".into(), 2)]);
    }

    #[test]
    fn positions_after_insert_in_middle() {
        let existing = vec![("a".into(), 0), ("b".into(), 1), ("c".into(), 2)];
        let result = positions_after_insert(&existing, 1);
        assert_eq!(result, vec![("a".into(), 0), ("b".into(), 2), ("c".into(), 3)]);
    }

    #[test]
    fn positions_after_move_forward() {
        let existing = vec![("a".into(), 0), ("b".into(), 1), ("c".into(), 2)];
        let result = positions_after_move(&existing, 0, 2);
        // a moves from 0→2, b shifts 1→0, c shifts 2→1
        assert_eq!(result, vec![("a".into(), 2), ("b".into(), 0), ("c".into(), 1)]);
    }

    #[test]
    fn positions_after_move_backward() {
        let existing = vec![("a".into(), 0), ("b".into(), 1), ("c".into(), 2)];
        let result = positions_after_move(&existing, 2, 0);
        // c moves from 2→0, a shifts 0→1, b shifts 1→2
        assert_eq!(result, vec![("a".into(), 1), ("b".into(), 2), ("c".into(), 0)]);
    }

    #[test]
    fn positions_after_move_same_position() {
        let existing = vec![("a".into(), 0), ("b".into(), 1)];
        let result = positions_after_move(&existing, 0, 0);
        assert_eq!(result, vec![("a".into(), 0), ("b".into(), 1)]);
    }

    #[test]
    fn positions_after_move_adjacent_forward() {
        let existing = vec![("a".into(), 0), ("b".into(), 1)];
        let result = positions_after_move(&existing, 0, 1);
        // a moves from 0→1, b shifts 1→0
        assert_eq!(result, vec![("a".into(), 1), ("b".into(), 0)]);
    }

    #[test]
    fn positions_after_move_adjacent_backward() {
        let existing = vec![("a".into(), 0), ("b".into(), 1)];
        let result = positions_after_move(&existing, 1, 0);
        // b moves from 1→0, a shifts 0→1
        assert_eq!(result, vec![("a".into(), 1), ("b".into(), 0)]);
    }
}

use crate::core::error::IdError;

/// Resolve a short ID prefix to a full ID.
///
/// Returns the matched full ID if exactly one candidate starts with the prefix,
/// `IdError::Ambiguous` if multiple match, or `IdError::NotFound` if none match.
pub fn resolve_id(prefix: &str, candidates: &[&str]) -> Result<String, IdError> {
    let matches: Vec<&str> = candidates
        .iter()
        .copied()
        .filter(|id| id.starts_with(prefix))
        .collect();

    match matches.len() {
        0 => Err(IdError::NotFound { prefix: prefix.to_string() }),
        1 => Ok(matches[0].to_string()),
        _ => Err(IdError::Ambiguous {
            prefix: prefix.to_string(),
            matches: matches.iter().map(|s| s.to_string()).collect(),
        }),
    }
}

/// Compute the minimum unique prefix length for each ID in the set.
///
/// For each ID, find the shortest prefix that distinguishes it from every other ID.
/// Returns a vector of `(id, min_prefix_length)` pairs.
pub fn min_unique_prefixes(ids: &[&str]) -> Vec<(String, usize)> {
    if ids.is_empty() {
        return vec![];
    }
    ids.iter()
        .map(|&id| {
            let min_len = ids
                .iter()
                .filter(|&&other| other != id)
                .map(|&other| {
                    // Find the first position where id and other differ.
                    // The minimum prefix must extend at least that far.
                    let diff_pos = id
                        .chars()
                        .zip(other.chars())
                        .position(|(a, b)| a != b)
                        .unwrap_or(id.len());
                    diff_pos + 1
                })
                .max()
                .unwrap_or(1) // If it's the only ID, minimum prefix is 1 char
                .min(id.len());
            (id.to_string(), min_len)
        })
        .collect()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn resolve_id_exact_match() {
        let ids = vec!["a3x9k2", "a3bQ7f", "m8rT2p"];
        assert_eq!(resolve_id("a3x9k2", &ids), Ok("a3x9k2".to_string()));
    }

    #[test]
    fn resolve_id_short_unique() {
        let ids = vec!["a3x9k2", "a3bQ7f", "m8rT2p"];
        // "m" uniquely matches "m8rT2p"
        assert_eq!(resolve_id("m", &ids), Ok("m8rT2p".to_string()));
    }

    #[test]
    fn resolve_id_short_unique_longer_prefix() {
        let ids = vec!["a3x9k2", "a3bQ7f", "m8rT2p"];
        // "a3x" uniquely matches "a3x9k2"
        assert_eq!(resolve_id("a3x", &ids), Ok("a3x9k2".to_string()));
    }

    #[test]
    fn resolve_id_ambiguous() {
        let ids = vec!["a3x9k2", "a3bQ7f", "m8rT2p"];
        // "a3" matches both "a3x9k2" and "a3bQ7f"
        let result = resolve_id("a3", &ids);
        assert!(result.is_err());
        let err = result.unwrap_err();
        assert_eq!(
            err,
            IdError::Ambiguous {
                prefix: "a3".to_string(),
                matches: vec!["a3x9k2".to_string(), "a3bQ7f".to_string()]
            }
        );
    }

    #[test]
    fn resolve_id_not_found() {
        let ids = vec!["a3x9k2", "m8rT2p"];
        let result = resolve_id("zzz", &ids);
        assert_eq!(
            result,
            Err(IdError::NotFound { prefix: "zzz".to_string() })
        );
    }

    #[test]
    fn resolve_id_empty_candidates() {
        let ids: Vec<&str> = vec![];
        let result = resolve_id("a", &ids);
        assert_eq!(
            result,
            Err(IdError::NotFound { prefix: "a".to_string() })
        );
    }

    #[test]
    fn resolve_id_single_candidate() {
        let ids = vec!["only1"];
        assert_eq!(resolve_id("o", &ids), Ok("only1".to_string()));
    }

    #[test]
    fn id_error_display_not_found() {
        let err = IdError::NotFound { prefix: "xyz".to_string() };
        assert_eq!(err.to_string(), "no match for ID prefix 'xyz'");
    }

    #[test]
    fn id_error_display_ambiguous() {
        let err = IdError::Ambiguous {
            prefix: "a3".to_string(),
            matches: vec!["a3x9k2".to_string(), "a3bQ7f".to_string()],
        };
        assert_eq!(
            err.to_string(),
            "ambiguous ID prefix 'a3' matches: a3x9k2, a3bQ7f"
        );
    }

    #[test]
    fn min_unique_prefixes_empty() {
        let ids: Vec<&str> = vec![];
        assert!(min_unique_prefixes(&ids).is_empty());
    }

    #[test]
    fn min_unique_prefixes_single() {
        let ids = vec!["abc123"];
        let result = min_unique_prefixes(&ids);
        assert_eq!(result, vec![("abc123".to_string(), 1)]);
    }

    #[test]
    fn min_unique_prefixes_distinct_first_char() {
        let ids = vec!["abc", "xyz"];
        let result = min_unique_prefixes(&ids);
        assert_eq!(result, vec![("abc".to_string(), 1), ("xyz".to_string(), 1)]);
    }

    #[test]
    fn min_unique_prefixes_shared_prefix() {
        let ids = vec!["a3x9k2", "a3bQ7f", "m8rT2p"];
        let result = min_unique_prefixes(&ids);
        // "m8rT2p" needs 1 char (m is unique first char)
        // "a3x9k2" and "a3bQ7f" share "a3", differ at 3rd char
        // so they need 3 chars each
        let map: std::collections::HashMap<String, usize> =
            result.into_iter().collect();
        assert_eq!(*map.get("m8rT2p").unwrap(), 1);
        assert_eq!(*map.get("a3x9k2").unwrap(), 3);
        assert_eq!(*map.get("a3bQ7f").unwrap(), 3);
    }

    #[test]
    fn min_unique_prefixes_very_similar() {
        let ids = vec!["abcdef", "abcdeg"];
        let result = min_unique_prefixes(&ids);
        let map: std::collections::HashMap<String, usize> =
            result.into_iter().collect();
        // They differ at position 5 (0-indexed), so need 6 chars
        assert_eq!(*map.get("abcdef").unwrap(), 6);
        assert_eq!(*map.get("abcdeg").unwrap(), 6);
    }

    #[test]
    fn min_unique_prefixes_one_is_prefix_of_other() {
        let ids = vec!["abc", "abcd"];
        let result = min_unique_prefixes(&ids);
        let map: std::collections::HashMap<String, usize> =
            result.into_iter().collect();
        // "abc" is a prefix of "abcd", so "abc" needs all 3 chars
        // "abcd" needs all 4 chars to distinguish from "abc"
        assert_eq!(*map.get("abc").unwrap(), 3);
        assert_eq!(*map.get("abcd").unwrap(), 4);
    }
}

use crate::core::types::{
    Board, Column, ColumnChanges, EntityTable, Priority, SqlParam, Task, TaskChanges,
};

// ── Read queries (static SQL strings) ──────────────────────────────────────

/// SELECT a board by its ID.
pub fn query_board_by_id() -> &'static str {
    "SELECT id, name, created_at, updated_at FROM board WHERE id = ?1"
}

/// SELECT columns for a board, ordered by position.
pub fn query_columns_by_board() -> &'static str {
    "SELECT id, board_id, name, position, created_at, updated_at FROM column_ WHERE board_id = ?1 ORDER BY position"
}

/// SELECT tasks for a board (via column), ordered by column and position.
pub fn query_tasks_by_board() -> &'static str {
    "SELECT t.id, t.column_id, t.title, t.description, t.priority_id, t.position, t.created_at, t.updated_at FROM task t JOIN column_ c ON t.column_id = c.id WHERE c.board_id = ?1 ORDER BY t.column_id, t.position"
}

/// SELECT all priorities.
pub fn query_priorities() -> &'static str {
    "SELECT id, name FROM priority ORDER BY name"
}

/// SELECT all boards, ordered by name.
pub fn query_all_boards() -> &'static str {
    "SELECT id, name, created_at, updated_at FROM board ORDER BY name"
}

// ── Write query constructors ───────────────────────────────────────────────

/// Build an INSERT statement for a board.
pub fn insert_board_sql(board: &Board) -> (String, Vec<SqlParam>) {
    let sql = "INSERT INTO board (id, name, created_at, updated_at) VALUES (?1, ?2, ?3, ?4)".to_string();
    let params = vec![
        SqlParam::Text(board.id.clone()),
        SqlParam::Text(board.name.clone()),
        SqlParam::Text(board.created_at.clone()),
        SqlParam::Text(board.updated_at.clone()),
    ];
    (sql, params)
}

/// Build an INSERT statement for a column.
pub fn insert_column_sql(column: &Column) -> (String, Vec<SqlParam>) {
    let sql = "INSERT INTO column_ (id, board_id, name, position, created_at, updated_at) VALUES (?1, ?2, ?3, ?4, ?5, ?6)".to_string();
    let params = vec![
        SqlParam::Text(column.id.clone()),
        SqlParam::Text(column.board_id.clone()),
        SqlParam::Text(column.name.clone()),
        SqlParam::Int(column.position),
        SqlParam::Text(column.created_at.clone()),
        SqlParam::Text(column.updated_at.clone()),
    ];
    (sql, params)
}

/// Build an INSERT statement for a task.
pub fn insert_task_sql(task: &Task) -> (String, Vec<SqlParam>) {
    let sql = "INSERT INTO task (id, column_id, title, description, priority_id, position, created_at, updated_at) VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7, ?8)".to_string();
    let params = vec![
        SqlParam::Text(task.id.clone()),
        SqlParam::Text(task.column_id.clone()),
        SqlParam::Text(task.title.clone()),
        SqlParam::Text(task.description.clone()),
        SqlParam::Text(task.priority_id.clone()),
        SqlParam::Int(task.position),
        SqlParam::Text(task.created_at.clone()),
        SqlParam::Text(task.updated_at.clone()),
    ];
    (sql, params)
}

/// Build an UPDATE statement for a task based on the provided changes.
pub fn update_task_sql(id: &str, changes: &TaskChanges) -> (String, Vec<SqlParam>) {
    let mut sets = Vec::new();
    let mut params = Vec::new();

    if let Some(ref title) = changes.title {
        sets.push("title = ?".to_string());
        params.push(SqlParam::Text(title.clone()));
    }
    if let Some(ref description) = changes.description {
        sets.push("description = ?".to_string());
        params.push(SqlParam::Text(description.clone()));
    }
    if let Some(ref priority_id) = changes.priority_id {
        sets.push("priority_id = ?".to_string());
        params.push(SqlParam::Text(priority_id.clone()));
    }
    if let Some(ref column_id) = changes.column_id {
        sets.push("column_id = ?".to_string());
        params.push(SqlParam::Text(column_id.clone()));
    }
    if let Some(position) = changes.position {
        sets.push("position = ?".to_string());
        params.push(SqlParam::Int(position));
    }

    params.push(SqlParam::Text(id.to_string()));
    let sql = format!(
        "UPDATE task SET {}, updated_at = datetime('now') WHERE id = ?{}",
        sets.join(", "),
        params.len()
    );
    (sql, params)
}

/// Build an UPDATE statement for a column based on the provided changes.
pub fn update_column_sql(id: &str, changes: &ColumnChanges) -> (String, Vec<SqlParam>) {
    let mut sets = Vec::new();
    let mut params = Vec::new();

    if let Some(ref name) = changes.name {
        sets.push("name = ?".to_string());
        params.push(SqlParam::Text(name.clone()));
    }
    if let Some(position) = changes.position {
        sets.push("position = ?".to_string());
        params.push(SqlParam::Int(position));
    }

    params.push(SqlParam::Text(id.to_string()));
    let sql = format!(
        "UPDATE column_ SET {}, updated_at = datetime('now') WHERE id = ?{}",
        sets.join(", "),
        params.len()
    );
    (sql, params)
}

/// Build a DELETE statement for a task by ID.
pub fn delete_task_sql(id: &str) -> (String, Vec<SqlParam>) {
    let sql = "DELETE FROM task WHERE id = ?1".to_string();
    let params = vec![SqlParam::Text(id.to_string())];
    (sql, params)
}

/// Build a DELETE statement for a column by ID.
pub fn delete_column_sql(id: &str) -> (String, Vec<SqlParam>) {
    let sql = "DELETE FROM column_ WHERE id = ?1".to_string();
    let params = vec![SqlParam::Text(id.to_string())];
    (sql, params)
}

/// Build a DELETE statement for all tasks in a column.
pub fn delete_tasks_by_column_sql(column_id: &str) -> (String, Vec<SqlParam>) {
    let sql = "DELETE FROM task WHERE column_id = ?1".to_string();
    let params = vec![SqlParam::Text(column_id.to_string())];
    (sql, params)
}

/// Build an UPDATE statement to move all tasks from one column to another.
pub fn move_tasks_to_column_sql(from_column_id: &str, to_column_id: &str) -> (String, Vec<SqlParam>) {
    let sql = "UPDATE task SET column_id = ?1 WHERE column_id = ?2".to_string();
    let params = vec![
        SqlParam::Text(to_column_id.to_string()),
        SqlParam::Text(from_column_id.to_string()),
    ];
    (sql, params)
}

/// Build an UPDATE statement for the position of an entity in the given table.
pub fn update_position_sql(table: EntityTable, id: &str, position: i32) -> (String, Vec<SqlParam>) {
    let table_name = table.table_name();
    let sql = format!(
        "UPDATE {} SET position = ?1, updated_at = datetime('now') WHERE id = ?2",
        table_name
    );
    let params = vec![SqlParam::Int(position), SqlParam::Text(id.to_string())];
    (sql, params)
}

/// Build an INSERT statement for a priority.
pub fn insert_priority_sql(priority: &Priority) -> (String, Vec<SqlParam>) {
    let sql = "INSERT INTO priority (id, name) VALUES (?1, ?2)".to_string();
    let params = vec![
        SqlParam::Text(priority.id.clone()),
        SqlParam::Text(priority.name.clone()),
    ];
    (sql, params)
}

