        let app = App::with_state(state);

        let lengths = get_min_prefix_lengths(&app);
        assert_eq!(*lengths.get("m8rT2p").unwrap(), 1);
        assert_eq!(*lengths.get("a3x9k2").unwrap(), 3);
        assert_eq!(*lengths.get("a3bQ7f").unwrap(), 3);
    }
